/* global console, process */
import { spawn } from 'node:child_process';
import { existsSync } from 'node:fs';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterRuntimePath = existsSync(monsterPath) ? monsterPath : gnexecPath;

if (!existsSync(monsterRuntimePath)) {
  console.error(`Monster runtime not found at ${monsterRuntimePath}`);
  process.exit(1);
}

const testUserIds = Array.from({ length: 100 }, (_, i) => `user${i}`);

function percentile(sorted, ratio) {
  if (sorted.length === 0) return 0;
  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(latencies) {
  const sorted = [...latencies].sort((a, b) => a - b);
  const sum = sorted.reduce((acc, v) => acc + v, 0);
  return {
    count: sorted.length,
    p50_us: percentile(sorted, 0.50),
    p95_us: percentile(sorted, 0.95),
    p99_us: percentile(sorted, 0.99),
    max_us: sorted[sorted.length - 1] ?? 0,
    mean_us: sum / Math.max(1, sorted.length),
  };
}

async function runMonsterResident(requests, depth = 20, env = {}) {
  return new Promise((resolve, reject) => {
    const child = spawn(monsterRuntimePath, [
      '--resident-jsonl',
      path.resolve(__dirname, 'foil-workload.ts'),
    ], {
      env: { ...process.env, ...env },
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    const results = [];
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');

    child.stdout.on('data', (chunk) => {
      chunk.trim().split('\n').forEach(line => {
        if (line) {
          try {
            const obj = JSON.parse(line);
            if (obj.ok && obj.elapsed_ns !== undefined) {
              results.push(obj.elapsed_ns / 1000); // Convert ns to µs
            }
          } catch (e) {
            // Ignore parse errors
          }
        }
      });
    });

    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });

    child.on('error', reject);
    child.on('close', (code) => {
      if (code !== 0 && stderr) {
        reject(new Error(`Process exited with code ${code}: ${stderr}`));
      } else {
        resolve(results);
      }
    });

    // Send requests
    setImmediate(() => {
      requests.forEach((userId, index) => {
        const line = JSON.stringify({ userId, depth, index });
        child.stdin.write(line + '\n');
      });
      child.stdin.end();
    });
  });
}

async function runBenchmark(name, requests, depth = 20, naive = false) {
  const label = naive ? '[FOIL_NAIVE]' : '[OPTIMIZED]';
  console.log(`\n${name} ${label}`);
  console.log('─'.repeat(60));

  const env = naive ? { FOIL_NAIVE: '1' } : {};

  try {
    const latencies = await runMonsterResident(requests, depth, env);
    const stats = summarize(latencies);

    console.log(`  Requests: ${stats.count}`);
    console.log(`  p50: ${stats.p50_us.toFixed(1)} µs`);
    console.log(`  p95: ${stats.p95_us.toFixed(1)} µs`);
    console.log(`  p99: ${stats.p99_us.toFixed(1)} µs`);
    console.log(`  max: ${stats.max_us.toFixed(1)} µs`);
    console.log(`  mean: ${stats.mean_us.toFixed(1)} µs`);

    return stats;
  } catch (error) {
    console.error(`Error: ${error.message}`);
    return null;
  }
}

async function main() {
  console.log('🔥 FOIL Optimization Validation Benchmark');
  console.log('════════════════════════════════════════════════════════════════\n');
  console.log('Measures FOIL hot-loop optimizations via realistic CPU-bound work.\n');

  const workloads = [
    { name: '⚡ Light Load (1000 reqs, depth=10)', count: 1000, depth: 10 },
    { name: '⚡ Medium Load (5000 reqs, depth=20)', count: 5000, depth: 20 },
    { name: '⚡ Heavy Load (10000 reqs, depth=30)', count: 10000, depth: 30 },
  ];

  const results = [];

  try {
    for (const { name, count, depth } of workloads) {
      const requests = Array.from({ length: count }, (_, i) =>
        testUserIds[i % testUserIds.length]
      );

      const naiveStats = await runBenchmark(name, requests, depth, true);
      const optimizedStats = await runBenchmark(name, requests, depth, false);

      if (naiveStats && optimizedStats) {
        const improvement = ((naiveStats.p99_us - optimizedStats.p99_us) / naiveStats.p99_us) * 100;
        results.push({ name, naiveStats, optimizedStats, improvement });
      }
    }

    console.log('\n' + '═'.repeat(60));
    console.log('FOIL OPTIMIZATION GAINS');
    console.log('═'.repeat(60));

    results.forEach(({ name, naiveStats, optimizedStats, improvement }) => {
      console.log(`\n${name}`);
      console.log(`  FOIL_NAIVE p99:  ${naiveStats.p99_us.toFixed(1)} µs`);
      console.log(`  OPTIMIZED p99:   ${optimizedStats.p99_us.toFixed(1)} µs`);
      console.log(`  Improvement:     ${improvement > 0 ? '✓' : '✗'} ${Math.abs(improvement).toFixed(1)}%`);
      if (improvement > 0) {
        console.log(`  Speedup:         ${(naiveStats.p99_us / optimizedStats.p99_us).toFixed(2)}×`);
      }
    });

    process.exit(0);
  } catch (error) {
    console.error('Error:', error.message);
    process.exit(1);
  }
}

main();
